anti_pattern:
let s1 = String::from("hello");
let s2 = s1;
println!("{}", s1); // Error: value borrowed here after move

good_pattern:
let s1 = String::from("hello");
let s2 = &s1;
println!("{}", s1); // Valid

anti_pattern:
let mut s = String::from("hello");
let r1 = &s;
let r2 = &mut s;
println!("{} and {}", r1, r2);

good_pattern:
let mut s = String::from("hello");
{
    let r1 = &s;
    println!("{}", r1);
}
let r2 = &mut s;
println!("{}", r2);

anti_pattern:
let some_value = Some(3);
match some_value {
    Some(3) => println!("three"),
}

good_pattern:
let some_value = Some(3);
match some_value {
    Some(3) => println!("three"),
    _ => (),
}

anti_pattern:
match config_max {
    Some(max) => println!("The maximum is configured to be {}", max),
    _ => (),
}

good_pattern:
if let Some(max) = config_max {
    println!("The maximum is configured to be {}", max);
}

anti_pattern:
fn read_username() -> String {
    let mut f = File::open("hello.txt").unwrap();
    let mut s = String::new();
    f.read_to_string(&mut s).unwrap();
    s
}

good_pattern:
fn read_username() -> Result<String, io::Error> {
    let mut s = String::new();
    File::open("hello.txt")?.read_to_string(&mut s)?;
    Ok(s)
}

anti_pattern:
struct ImportantExcerpt {
    part: &str,
}

good_pattern:
struct ImportantExcerpt<'a> {
    part: &'a str,
}

anti_pattern:
let mut v2 = Vec::new();
for i in &v1 {
    v2.push(i + 1);
}

let a = Box::new(List::Cons(5, Box::new(List::Nil)));
let b = List::Cons(3, a); // 'a' moved here
let c = List::Cons(4, a); // Error: use of moved value

good_pattern:
let a = Rc::new(List::Cons(5, Rc::new(List::Nil)));
let b = List::Cons(3, Rc::clone(&a));
let c = List::Cons(4, Rc::clone(&a));

anti_pattern:
let mut val = String::from("hi");
thread::spawn(move || { val.push_str(" there"); });
println!("{}", val);

good_pattern:
let (tx, rx) = mpsc::channel();
thread::spawn(move || { tx.send(String::from("hi")).unwrap(); });
let val = rx.recv().unwrap();

let counter = Arc::new(Mutex::new(0));
let counter_clone = Arc::clone(&counter);
thread::spawn(move || { *counter_clone.lock().unwrap() += 1; });

anti_pattern:
struct Screen<T: Draw> {
    components: Vec<T>,
} // Forces all components to be of the exact same type

good_pattern:
struct Screen {
    components: Vec<Box<dyn Draw>>,
} // Allows mixed types (e.g., Button, TextField)

unsafe fn dangerous() {}
unsafe {
    dangerous();
}

anti_pattern:
struct Slice<'a, T> {
    start: *const T,
    end: *const T,
} // Error: unused parameter 'a

good_pattern:
struct Slice<'a, T> {
    start: *const T,
    end: *const T,
    _marker: std::marker::PhantomData<&'a T>,
}

fn with_guard<F: FnOnce()>(f: F) {
    /* vital setup */
    let _res = std::panic::catch_unwind(std::panic::AssertUnwindSafe(f));
    /* vital teardown guaranteed */
}

anti_pattern:
async fn handle() {
    std::thread::sleep(std::time::Duration::from_secs(5)); // Blocks the entire executor
}

good_pattern:
async fn handle() {
    tokio::time::sleep(std::time::Duration::from_secs(5)).await; // Yields control
}

anti_pattern:
fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
    Poll::Pending
}

good_pattern:
fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
    self.state.waker = Some(cx.waker().clone());
    Poll::Pending
}

struct SharedData { value: Mutex<i32> } // Automatically Sync
fn assert_sync<T: Sync>() {}
assert_sync::<SharedData>();

anti_pattern:
extern "C" { fn c_print(s: *const i8); }
let s = "hello";
unsafe { c_print(s.as_ptr() as *const i8) } // Missing null terminator!

good_pattern:
#![no_std]
use core::cmp::Ordering;
fn compare(a: i32, b: i32) -> Ordering { a.cmp(&b) }

anti_pattern:
fn run(tasks: Vec<Task>) {
    let mut state = Vec::new();
    for task in tasks {
        state.push(task);
    }
} // Starts coding before the representation and invariants are designed

good_pattern:
struct SchedulerPlan {
    ready: std::collections::VecDeque<TaskId>,
    in_flight: std::collections::HashSet<TaskId>,
    results: std::collections::BTreeMap<TaskId, TaskResult>,
}
// ready preserves FIFO order; results use stable ordering for deterministic output

anti_pattern:
struct Connection {
    authenticated: bool,
    state: String,
}

good_pattern:
struct Connection {
    state: ConnectionState,
}

enum ConnectionState {
    Connected,
    Authenticated { user_id: UserId },
    Closed,
}

